import{_ as e,o as a,c as n,i as o}from"./chunks/framework.DP1yFSuu.js";const h=JSON.parse('{"title":"Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"patterns/index.md","filePath":"patterns/index.md"}'),r={name:"patterns/index.md"};function i(s,t,l,d,c,p){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="patterns" tabindex="-1">Patterns <a class="header-anchor" href="#patterns" aria-label="Permalink to &quot;Patterns&quot;">​</a></h1><p>Patterns are reusable solutions to common design problems. Unlike individual components, patterns combine multiple components, layout strategies, and interaction behaviors into cohesive experiences that solve a specific user need.</p><h2 id="patterns-vs-components" tabindex="-1">Patterns vs. Components <a class="header-anchor" href="#patterns-vs-components" aria-label="Permalink to &quot;Patterns vs. Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Components</th><th>Patterns</th></tr></thead><tbody><tr><td>Scope</td><td>Single UI element</td><td>Composition of multiple elements</td></tr><tr><td>Reuse</td><td>Imported as a package</td><td>Copied and adapted per context</td></tr><tr><td>Ownership</td><td>Design system team</td><td>Product teams</td></tr><tr><td>Examples</td><td><code>co-button</code>, <code>co-input</code></td><td>Form validation, navigation layout</td></tr></tbody></table><blockquote><p><strong>Tip:</strong> Think of components as the vocabulary and patterns as the grammar. Components give you the building blocks; patterns show you how to assemble them into meaningful interfaces.</p></blockquote><h2 id="available-patterns" tabindex="-1">Available Patterns <a class="header-anchor" href="#available-patterns" aria-label="Permalink to &quot;Available Patterns&quot;">​</a></h2><h3 id="forms-validation" tabindex="-1"><a href="./forms.html">Forms &amp; Validation</a> <a class="header-anchor" href="#forms-validation" aria-label="Permalink to &quot;[Forms &amp; Validation](./forms.md)&quot;">​</a></h3><p>Layout patterns for forms, inline and summary validation, error messaging, required field indicators, and submission handling.</p><h3 id="layout" tabindex="-1"><a href="./layout.html">Layout</a> <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;[Layout](./layout.md)&quot;">​</a></h3><p>Page structure, grid system, responsive breakpoints, sidebar layouts, content areas, and spacing rhythm.</p><h2 id="when-to-create-a-new-pattern" tabindex="-1">When to Create a New Pattern <a class="header-anchor" href="#when-to-create-a-new-pattern" aria-label="Permalink to &quot;When to Create a New Pattern&quot;">​</a></h2><p>Before proposing a new pattern, consider the following criteria:</p><ol><li><strong>Frequency</strong> -- The solution is needed in three or more distinct contexts across products.</li><li><strong>Consistency</strong> -- Inconsistent implementations are causing user confusion or accessibility issues.</li><li><strong>Complexity</strong> -- The solution involves coordinating multiple components with non-obvious interaction logic.</li><li><strong>Stability</strong> -- The underlying components are mature and unlikely to change significantly.</li></ol><h2 id="contributing-a-pattern" tabindex="-1">Contributing a Pattern <a class="header-anchor" href="#contributing-a-pattern" aria-label="Permalink to &quot;Contributing a Pattern&quot;">​</a></h2><p>Patterns are documented collaboratively. To propose a new pattern:</p><ol><li>Open an issue in the <code>@cobalt/design-system</code> repository using the <strong>Pattern Proposal</strong> template.</li><li>Include at least two real-world examples from existing products.</li><li>Draft the pattern documentation following the structure used in existing pattern pages.</li><li>Submit a pull request for review by the design system team.</li></ol><h2 id="using-patterns-in-your-project" tabindex="-1">Using Patterns in Your Project <a class="header-anchor" href="#using-patterns-in-your-project" aria-label="Permalink to &quot;Using Patterns in Your Project&quot;">​</a></h2><p>Patterns are not shipped as installable packages. Instead, use them as reference implementations:</p><p>Adapt the documented markup to fit your product&#39;s specific requirements while preserving the interaction and accessibility conventions described in each pattern.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/components/">Component Library</a> -- Full reference for all <code>co-</code> components</li><li><a href="/cobalt-design-system/tokens/">Design Tokens</a> -- Spacing, color, and typography tokens used in patterns</li><li><a href="/cobalt-design-system/foundations/">Foundations</a> -- Core principles behind Cobalt&#39;s design decisions</li></ul>',21)])])}const m=e(r,[["render",i]]);export{h as __pageData,m as default};
